export interface LayerCosts {
  symbolic: number;
  lexical: number;
  semantic: number;
}

export interface CostBudget {
  maxCost: number;
  preferredLayers?: ('symbolic' | 'lexical' | 'semantic')[];
}

export interface SearchStrategy {
  layers: ('symbolic' | 'lexical' | 'semantic')[];
  weights: { semantic: number; lexical: number; symbolic: number };
  estimatedCost: number;
  reasoning: string;
}

export interface CostAwareResult {
  results: HybridSearchResult[];
  strategy: SearchStrategy;
  actualCost: number;
  budgetRemaining: number;
}

export const DEFAULT_LAYER_COSTS: LayerCosts = {
  symbolic: 1,
  lexical: 2,
  semantic: 5,
};

export class CostAwareSearchManager {
  private hybridSearch: HybridSearchManager;
  private queryAnalyzer: QueryAnalyzer;
  private costs: LayerCosts;

  constructor(
    hybridSearch: HybridSearchManager,
    queryAnalyzer: QueryAnalyzer,
    costs: LayerCosts = DEFAULT_LAYER_COSTS
  ) {
    this.hybridSearch = hybridSearch;
    this.queryAnalyzer = queryAnalyzer;
    this.costs = costs;
  }

  selectStrategy(query: string, budget?: CostBudget): SearchStrategy {
    const analysis = this.queryAnalyzer.analyze(query);
    const availableLayers: ('symbolic' | 'lexical' | 'semantic')[] = [];
    let totalCost = 0;

    // Symbolic is always cheap, add first
    if (!budget || totalCost + this.costs.symbolic <= budget.maxCost) {
      availableLayers.push('symbolic');
      totalCost += this.costs.symbolic;
    }

    // Lexical for keyword-heavy queries
    if (!budget || totalCost + this.costs.lexical <= budget.maxCost) {
      availableLayers.push('lexical');
      totalCost += this.costs.lexical;
    }

    // Semantic for conceptual queries (most expensive)
    if (!budget || totalCost + this.costs.semantic <= budget.maxCost) {
      if (analysis.questionType === 'conceptual' || analysis.confidence < 0.7) {
        availableLayers.push('semantic');
        totalCost += this.costs.semantic;
      }
    }

    // Calculate weights based on available layers
    const weights = this.calculateWeights(availableLayers, analysis);

    return {
      layers: availableLayers,
      weights,
      estimatedCost: totalCost,
      reasoning: this.generateReasoning(analysis, availableLayers, budget),
    };
  }

  private calculateWeights(
    layers: string[],
    analysis: QueryAnalysis
  ): { semantic: number; lexical: number; symbolic: number } {
    const weights = { semantic: 0, lexical: 0, symbolic: 0 };

    if (layers.length === 0) return weights;

    // Distribute weight based on query type
    if (layers.includes('semantic')) {
      weights.semantic = analysis.questionType === 'conceptual' ? 0.5 : 0.3;
    }
    if (layers.includes('lexical')) {
      weights.lexical = 0.3;
    }
    if (layers.includes('symbolic')) {
      weights.symbolic = analysis.entities.length > 0 ? 0.4 : 0.2;
    }

    // Normalize to sum to 1
    const sum = weights.semantic + weights.lexical + weights.symbolic;
    if (sum > 0) {
      weights.semantic /= sum;
      weights.lexical /= sum;
      weights.symbolic /= sum;
    }

    return weights;
  }

  private generateReasoning(
    analysis: QueryAnalysis,
    layers: string[],
    budget?: CostBudget
  ): string {
    const parts: string[] = [];

    if (layers.includes('semantic')) {
      parts.push('semantic layer for conceptual matching');
    }
    if (layers.includes('lexical')) {
      parts.push('lexical layer for keyword matching');
    }
    if (layers.includes('symbolic')) {
      parts.push('symbolic layer for metadata filtering');
    }

    if (budget) {
      parts.push(`within budget of ${budget.maxCost} units`);
    }

    return `Selected ${parts.join(', ')}`;
  }

  async search(
    graph: KnowledgeGraph,
    query: string,
    budget?: CostBudget
  ): Promise<CostAwareResult> {
    const strategy = this.selectStrategy(query, budget);

    const results = await this.hybridSearch.searchWithEntities(graph, query, {
      semanticWeight: strategy.weights.semantic,
      lexicalWeight: strategy.weights.lexical,
      symbolicWeight: strategy.weights.symbolic,
    });

    return {
      results,
      strategy,
      actualCost: strategy.estimatedCost,
      budgetRemaining: budget ? budget.maxCost - strategy.estimatedCost : 0,
    };
  }
}

import { HybridSearchManager, HybridSearchResult } from './HybridSearchManager.js';
import { QueryAnalyzer, QueryAnalysis } from './QueryAnalyzer.js';
import type { KnowledgeGraph } from '../types/index.js';

{
  name: 'search_auto',
  description: 'Automatically select and execute optimal search strategy based on query characteristics and optional cost budget. Returns results with strategy explanation and cost breakdown.',
  inputSchema: {
    type: 'object',
    properties: {
      query: {
        type: 'string',
        description: 'Search query text',
      },
      maxCost: {
        type: 'number',
        description: 'Maximum cost budget in abstract units (symbolic=1, lexical=2, semantic=5). If omitted, no budget constraint.',
      },
      limit: {
        type: 'number',
        default: 10,
        description: 'Maximum results to return',
      },
    },
    required: ['query'],
  },
},

case 'search_auto': {
  const { query, maxCost, limit = 10 } = args;

  // NOTE: Requires rankedSearch getter added to ManagerContext (Sprint 11.1)
  const hybridSearch = new HybridSearchManager(
    ctx.semanticSearch,
    ctx.rankedSearch
  );
  const queryAnalyzer = new QueryAnalyzer();
  // Integrates with existing QueryCostEstimator from Phase 10
  const costAwareSearch = new CostAwareSearchManager(
    hybridSearch,
    queryAnalyzer,
    DEFAULT_LAYER_COSTS
  );

  const graph = await ctx.storage.loadGraph();

  const budget = maxCost !== undefined ? { maxCost } : undefined;
  const result = await costAwareSearch.search(graph, query, budget);

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        query,
        strategy: {
          layers: result.strategy.layers,
          weights: result.strategy.weights,
          reasoning: result.strategy.reasoning,
        },
        cost: {
          estimated: result.strategy.estimatedCost,
          actual: result.actualCost,
          budgetRemaining: result.budgetRemaining,
        },
        resultCount: Math.min(result.results.length, limit),
        results: result.results.slice(0, limit).map(r => ({
          name: r.entity.name,
          entityType: r.entity.entityType,
          score: r.score,
          observations: r.entity.observations.slice(0, 3),
        })),
      }, null, 2),
    }],
  };
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  CostAwareSearchManager,
  DEFAULT_LAYER_COSTS,
  LayerCosts,
  CostBudget,
} from '../../../src/search/CostAwareSearchManager.js';
import { HybridSearchManager } from '../../../src/search/HybridSearchManager.js';
import { QueryAnalyzer } from '../../../src/search/QueryAnalyzer.js';

describe('CostAwareSearchManager', () => {
  let mockHybridSearch: HybridSearchManager;
  let mockQueryAnalyzer: QueryAnalyzer;
  let manager: CostAwareSearchManager;

  beforeEach(() => {
    mockHybridSearch = {
      searchWithEntities: vi.fn().mockResolvedValue([]),
    } as unknown as HybridSearchManager;

    mockQueryAnalyzer = {
      analyze: vi.fn().mockReturnValue({
        query: 'test',
        entities: [],
        temporalRange: null,
        questionType: 'factual',
        confidence: 0.8,
      }),
    } as unknown as QueryAnalyzer;

    manager = new CostAwareSearchManager(
      mockHybridSearch,
      mockQueryAnalyzer,
      DEFAULT_LAYER_COSTS
    );
  });

describe('DEFAULT_LAYER_COSTS', () => {
  it('should have correct default costs', () => {
    expect(DEFAULT_LAYER_COSTS.symbolic).toBe(1);
    expect(DEFAULT_LAYER_COSTS.lexical).toBe(2);
    expect(DEFAULT_LAYER_COSTS.semantic).toBe(5);
  });
});

describe('selectStrategy', () => {
  it('should select all layers when no budget constraint', () => {
    const strategy = manager.selectStrategy('what is the meaning of life');
    expect(strategy.layers).toContain('symbolic');
    expect(strategy.layers).toContain('lexical');
  });

  it('should include semantic for conceptual queries', () => {
    (mockQueryAnalyzer.analyze as ReturnType<typeof vi.fn>).mockReturnValue({
      query: 'what is the meaning of life',
      entities: [],
      temporalRange: null,
      questionType: 'conceptual',
      confidence: 0.9,
    });

    const strategy = manager.selectStrategy('what is the meaning of life');
    expect(strategy.layers).toContain('semantic');
  });

  it('should respect budget constraints', () => {
    const budget: CostBudget = { maxCost: 3 };
    const strategy = manager.selectStrategy('test query', budget);

    // With maxCost=3, can afford symbolic(1) + lexical(2) = 3
    expect(strategy.estimatedCost).toBeLessThanOrEqual(3);
    expect(strategy.layers).not.toContain('semantic');
  });

  it('should calculate correct estimated cost', () => {
    const budget: CostBudget = { maxCost: 100 };
    (mockQueryAnalyzer.analyze as ReturnType<typeof vi.fn>).mockReturnValue({
      query: 'test',
      entities: [],
      temporalRange: null,
      questionType: 'conceptual',
      confidence: 0.5,
    });

    const strategy = manager.selectStrategy('test', budget);

    // All layers: 1 + 2 + 5 = 8
    expect(strategy.estimatedCost).toBe(8);
  });

  it('should generate reasoning string', () => {
    const strategy = manager.selectStrategy('test query');
    expect(strategy.reasoning).toBeDefined();
    expect(strategy.reasoning.length).toBeGreaterThan(0);
  });
});

describe('weight calculation', () => {
  it('should normalize weights to sum to 1', () => {
    const strategy = manager.selectStrategy('test query');
    const sum = strategy.weights.semantic + strategy.weights.lexical + strategy.weights.symbolic;
    expect(sum).toBeCloseTo(1, 5);
  });

  it('should give higher symbolic weight when entities detected', () => {
    (mockQueryAnalyzer.analyze as ReturnType<typeof vi.fn>).mockReturnValue({
      query: 'Alice from TechCorp',
      entities: [{ name: 'Alice', type: 'person' }, { name: 'TechCorp', type: 'organization' }],
      temporalRange: null,
      questionType: 'factual',
      confidence: 0.9,
    });

    const strategy = manager.selectStrategy('Alice from TechCorp');
    expect(strategy.weights.symbolic).toBeGreaterThan(0.2);
  });
});

  describe('search', () => {
    it('should execute search with selected strategy', async () => {
      const graph = { entities: [], relations: [] };
      const result = await manager.search(graph, 'test query');

      expect(mockHybridSearch.searchWithEntities).toHaveBeenCalled();
      expect(result.results).toBeDefined();
      expect(result.strategy).toBeDefined();
      expect(result.actualCost).toBeDefined();
    });

    it('should return budget remaining', async () => {
      const graph = { entities: [], relations: [] };
      const budget: CostBudget = { maxCost: 10 };
      const result = await manager.search(graph, 'test query', budget);

      expect(result.budgetRemaining).toBeDefined();
      expect(result.budgetRemaining).toBeGreaterThanOrEqual(0);
    });
  });
});

